#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to calculate GCD using Euclidean algorithm
int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        long long product = 1;
        for (int i = 0; i < N; i++) {
            product = (product * A[i]) % 1000000007;
        }
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int g = gcd(A[i], A[j]);
                if (g > 1) {
                    A[i] /= g;
                    A[j] /= g;
                    i = -1;
                    break;
                }
            }
        }
        product = 1;
        for (int i = 0; i < N; i++) {
            product = (product * A[i]) % 1000000007;
        }
        printf("%lld\n", product);
        free(A);
    }
    return 0;
}

