        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            long product = 1;
            for (int i = 0; i < N; i++) {
                product = (product * A[i]) % 1000000007;
            }
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    int g = gcd(A[i], A[j]);
                    if (g > 1) {
                        A[i] /= g;
                        A[j] /= g;
                        i = -1;
                        break;
                    }
                }
            }
            product = 1;
            for (int i = 0; i < N; i++) {
                product = (product * A[i]) % 1000000007;
            }
            System.out.println(product);
        }
