const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function gcd(a, b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

let t = parseInt(lines[idx++]);
while (t--) {
    let n = parseInt(lines[idx++]);
    let a = lines[idx++].split(' ').map(x => parseInt(x));
    let product = 1;
    for (let i = 0; i < n; i++) {
        product = (product * a[i]) % 1000000007;
    }
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            let g = gcd(a[i], a[j]);
            if (g > 1) {
                a[i] = Math.floor(a[i] / g);
                a[j] = Math.floor(a[j] / g);
                i = -1;
                break;
            }
        }
    }
    product = 1;
    for (let i = 0; i < n; i++) {
        product = (product * a[i]) % 1000000007;
